    "text_content": "Campo de geração e envio obrigatório pela iniciadora (client) e o seu valor deve ser “espelhado” pela detentora (server) no cabeçalho de resposta.\\n\", \"schema\": { \"type\": \"string\", \"format\": \"uuid\", \"minLength\": 1, \"maxLength\": 36, \"pattern\": \"^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$\", \"example\": \"d78fc4e5-37ca-4da3-adf2-9b082bf92280\" } }, \"x-v\": { \"description\": \"Cabeçalho que indica a versão implementada da API pela instituição financeira para atender à solicitação. Deve ser preenchido de forma completa, por exemplo: x-v : 1.0.2.\\n\", \"required\": true, \"schema\": { \"type\": \"string\", \"pattern\": \"^\\\\d+\\\\.\\\\d+\\\\.\\\\d+$\", \"example\": \"1.0.0\" } } }, \"content\": { \"application/jwt\": { \"schema\": { \"type\": \"object\", \"required\": [ \"data\", \"links\", \"meta\" ], \"properties\": { \"data\": { \"type\": \"object\", \"required\": [ \"recurringPaymentId\", \"endToEndId\", \"date\", \"creationDateTime\", \"statusUpdateDateTime\", \"status\", \"cnpjInitiator\", \"payment\", \"document\", \"localInstrument\" ], \"properties\": { \"recurringPaymentId\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 100, \"pattern\": \"^[a-zA-Z0-9][a-zA-Z0-9\\\\-]{0,99}$\", \"example\": \"TXpRMU9UQTROMWhZV2xSU1FUazJSMDl\", \"description\": \"Código ou identificador único informado pela instituição detentora da conta para representar a iniciação de pagamento.",
