    "id": "automatic_payments_2.2.0_PATCH_pix_recurring-payments_recurringPaymentId_chunk_29_2be97a31",
    "text_content": "1-9])T(?:[01]\\\\d|2[0123]):(?:[012345]\\\\d):(?:[012345]\\\\d)Z$\", \"example\": \"2021-05-21T08:30:00Z\" }, \"cancelledBy\": { \"type\": \"object\", \"description\": \"Informação relacionada ao usuário pagador que solicitou o cancelamento do pagamento.\", \"required\": [ \"document\" ], \"properties\": { \"document\": { \"type\": \"object\", \"description\": \"Objeto que consolida os dados do documento do usuário que solicitou o cancelamento.\", \"required\": [ \"identification\", \"rel\" ], \"properties\": { \"identification\": { \"type\": \"string\", \"maxLength\": 14, \"description\": \"Número do documento de identificação oficial do pagador ou recebedor, pessoa natural ou jurídica.\", \"example\": \"11111111111\", \"pattern\": \"^([0-9]{11})$|^([0-9A-Z]{12}[0-9]{2})$\" }, \"rel\": { \"type\": \"string\", \"description\": \"Tipo de documento de identificação oficial do pagador ou recebedor, pessoa natural ou jurídica.\", \"enum\": [ \"CPF\", \"CNPJ\" ] } } } } } } }, \"authorisationFlow\": { \"type\": \"string\", \"enum\": [ \"HYBRID_FLOW\", \"CIBA_FLOW\", \"FIDO_FLOW\" ], \"example\": \"HYBRID_FLOW\", \"description\": \"Campo condicional utilizado para identificar o fluxo de autorização em que o pagamento foi solicitado.\\n\\n[Restrição] Se CIBA ou FIDO, preenchimento obrigatório. Caso o campo não esteja presente no payload, subentende-se que o fluxo de autorização utilizado é o HYBRID_FLOW.\\n\" }, \"transactionIdentification\": { \"type\": \"string\", \"pattern\": \"^[a-zA-Z0-9]{1,35}$\", \"maxLength\": 35, \"example\": \"E00038166201907261559y6j6\", \"description\": \"Trata-se de um identificador de transação que deve ser retransmitido intacto pelo PSP do pagador ao gerar a ordem de pagamento. \\nEssa informação permitirá ao recebedor identificar e correlacionar a transferência, quando recebida, com a apresentação das instruções ao pagador. \\nOs caracteres permitidos no contexto do Pix para o campo txid (EMV 62-05) são:Letras minúsculas, de 'a' a 'z' Letras maiúsculas, de 'A' a 'z' Dígitos decimais, de '0' a '9'.\\n\\n[Restrição] Preenchimento condicional de acordo com o conteúdo do campo localInstument: \\n- MANU - O campo transactionIdentification não deve ser preenchido; \\n- DICT - O campo transactionIdentification não deve ser preenchido; \\n- INIC - O campo transactionIdentification deve ser preenchido obrigatoriamente e deve conter até 25 caracteres alfanuméricos ([a-z|A-Z|0-9]); \\n- AUTO – O campo transactionIdentification não deve ser preenchido.\\n\" }, \"document\": { \"type\": \"object\", \"description\": \"Informações do documento identificador do recebedor da transação.\", \"required\": [ \"identification\", \"rel\" ], \"properties\": { \"identification\": { \"type\": \"string\", \"pattern\": \"^([0-9]{11})$|^([0-9A-Z]{12}[0-9]{2})$\", \"minLength\": 11, \"maxLength\": 14, \"example\": \"11111111111111\", \"description\": \"Número do documento de identificação oficial do recebedor pessoa natural ou jurídica. \\nO valor informado deve ser igual a um dos valores enviados na etapa de criação do consentimento (dentro do array “/data/creditors”). \\nQuando não respeitada essa regra, deve ser retornado pelo detentor, de maneira síncrona, erro HTTP 422 - PAGAMENTO_DIVERGENTE_CONSENTIMENTO\\n\" }, \"rel\": { \"type\": \"string\", \"enum\": [ \"CPF\", \"CNPJ\" ], \"example\": \"CNPJ\", \"description\": \"Tipo do documento de identificação oficial do titular pessoa natural ou jurídica.\" } } }, \"proxy\": { \"type\": \"string\", \"description\": \"Chave cadastrada no DICT pertencente ao recebedor.",
    "title": "Cancelamento de solicitação de pagamento automático.",
    "url": "/pix/recurring-payments/{recurringPaymentId}",
