    "id": "automatic_payments_2.2.0_PATCH_pix_recurring-payments_recurringPaymentId_chunk_38_7cddab1d",
    "text_content": "Caso não seja enviado pela iniciadora, ou enviado inválido, a detentora deve gerar um x-fapi-interaction-id e retorná-lo na resposta com o HTTP status code 400. A iniciadora deve acatar o valor gerado pelo detentor e recebido na resposta.\\n\", \"schema\": \"[Circular Reference]\" } } }, \"401\": { \"description\": \"Cabeçalho de autenticação ausente/inválido ou token inválido\", \"content\": { \"application/json; charset=utf-8\": { \"schema\": \"[Circular Reference]\" } }, \"headers\": { \"x-fapi-interaction-id\": \"[Circular Reference]\" } }, \"403\": { \"description\": \"O token tem escopo incorreto ou uma política de segurança foi violada\", \"content\": { \"application/json; charset=utf-8\": { \"schema\": \"[Circular Reference]\" } }, \"headers\": { \"x-fapi-interaction-id\": \"[Circular Reference]\" } }, \"404\": { \"description\": \"O recurso solicitado não existe ou não foi implementado\", \"content\": { \"application/json; charset=utf-8\": { \"schema\": \"[Circular Reference]\" } }, \"headers\": { \"x-fapi-interaction-id\": \"[Circular Reference]\" } }, \"405\": { \"description\": \"O consumidor tentou acessar o recurso com um método não suportado\", \"content\": { \"application/json; charset=utf-8\": { \"schema\": \"[Circular Reference]\" } }, \"headers\": { \"x-fapi-interaction-id\": \"[Circular Reference]\" } }, \"406\": { \"description\": \"A solicitação continha um cabeçalho Accept diferente dos tipos de mídia permitidos ou um conjunto de caracteres diferente de UTF-8\", \"content\": { \"application/json; charset=utf-8\": { \"schema\": \"[Circular Reference]\" } }, \"headers\": { \"x-fapi-interaction-id\": \"[Circular Reference]\" } }, \"422\": { \"description\": \"Seguir as orientações presentes na descrição do endpoint\", \"content\": { \"application/jwt\": { \"schema\": { \"type\": \"object\", \"required\": [ \"errors\" ], \"properties\": { \"errors\": { \"type\": \"array\", \"minItems\": 1, \"maxItems\": 3, \"items\": { \"type\": \"object\", \"required\": [ \"code\", \"title\", \"detail\" ], \"properties\": { \"code\": { \"type\": \"string\", \"enum\": [ \"PAGAMENTO_NAO_PERMITE_CANCELAMENTO\", \"CANCELAMENTO_FORA_PERIODO_PERMITIDO\", \"PARAMETRO_INVALIDO\", \"PARAMETRO_NAO_INFORMADO\" ], \"example\": \"PAGAMENTO_NAO_PERMITE_CANCELAMENTO\", \"description\": \"- PAGAMENTO_NAO_PERMITE_CANCELAMENTO: Pagamento está com um status que não permite cancelamento.\\n- CANCELAMENTO_FORA_PERIODO_PERMITIDO: O usuário solicitou o cancelamento fora da janela de tempo permitido.\\n- PARAMETRO_INVALIDO: Os parâmetros informados não obedecem a formatação especificada.\\n- PARAMETRO_NAO_INFORMADO: Algum ou todos os campos obrigatórios não foram informados.\\n\" }, \"title\": { \"type\": \"string\", \"maxLength\": 255, \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"example\": \"O pagamento está com um status que não permite o cancelamento.\", \"description\": \"- PAGAMENTO_NAO_PERMITE_CANCELAMENTO: Pagamento está com um status que não permite cancelamento.\\n- CANCELAMENTO_FORA_PERIODO_PERMITIDO: O usuário solicitou o cancelamento fora da janela de tempo permitido.\\n- PARAMETRO_INVALIDO: Os parâmetros informados não obedecem a formatação especificada.\\n- PARAMETRO_NAO_INFORMADO: Algum ou todos os campos obrigatórios não foram informados.\\n\" }, \"detail\": { \"type\": \"string\", \"maxLength\": 2048, \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"example\": \"O pagamento está com um status que não permite o cancelamento.\", \"description\": \"- PAGAMENTO_NAO_PERMITE_CANCELAMENTO: Pagamento está com um status que não permite cancelamento.\\n- CANCELAMENTO_FORA_PERIODO_PERMITIDO: O usuário solicitou o cancelamento fora da janela de tempo permitido.\\n- PARAMETRO_INVALIDO: Os parâmetros informados não obedecem a formatação especificada.\\n- PARAMETRO_NAO_INFORMADO: Algum ou todos os campos obrigatórios não foram informados.\\n\" } } } }, \"meta\": \"[Circular Reference]\" } }, \"examples\": { \"Pagamento não permite cancelamento\": { \"summary\": \"Pagamento não permite cancelamento\", \"value\": { \"errors\": [ { \"code\": \"PAGAMENTO_NAO_PERMITE_CANCELAMENTO\", \"title\": \"O pagamento está com um status que não permite o cancelamento.\", \"detail\": \"O pagamento está com um status que não permite o cancelamento.\" } ], \"meta\": { \"requestDateTime\": \"2021-05-21T08:30:00Z\" } } } } } }, \"headers\": { \"x-fapi-interaction-id\": \"[Circular Reference]\" } }, \"500\": { \"description\": \"Ocorreu um erro no gateway da API ou no microsserviço\", \"content\": { \"application/json; charset=utf-8\": { \"schema\": \"[Circular Reference]\" } }, \"headers\": { \"x-fapi-interaction-id\": { \"description\": \"Um UUID [RFC4122](https://tools.ietf.org/html/rfc4122) usado como um ID de correlação entre request e response.",
