    "id": "automatic_payments_2.2.0_PATCH_recurring-consents_recurringConsentId_chunk_27_32a3d413",
    "text_content": "1-9])-(3[01]|[12][0-9]|0?[ 1-9])T(?:[01]\\\\d|2[0123]):(?:[012345]\\\\d):(?:[012345]\\\\d)Z$\", \"maxLength\": 20 }, \"recurringConfiguration\": { \"type\": \"object\", \"description\": \"Campo destinado a configuração dos diferentes produtos de pagamentos recorrentes.\", \"properties\": { \"automatic\": { \"type\": \"object\", \"description\": \"Definição da configuração de recorrência para pagamentos automáticos\", \"properties\": { \"maximumVariableAmount\": { \"type\": \"string\", \"pattern\": \"^((\\\\d{1,16}\\\\.\\\\d{2}))$\", \"minLength\": 4, \"maxLength\": 19, \"example\": \"1000000.12\", \"description\": \"Valor máximo permitido por cobrança, caso preenchido, representa um consentimento para pagamentos de valores variáveis.\\n\\n[Restrição] \\nCaso esse campo não seja enviado, a instituição detentora deve considerar o valor máximo do pagamento variável como indefinido, exceto em casos de edição exclusiva do campo “/data/creditors/name”;\\n\\nCaso informado, o valor desse campo não deve ser inferior ao valor definido no campo \\\"/data/recurringConfiguration/automatic/minimumVariableAmount\\\".\\n\" } } } } }, \"loggedUser\": { \"type\": \"object\", \"description\": \"Usuário (pessoa natural) que encontra-se logado na instituição Iniciadora de Pagamento.\\n\\n[Restrição] Objeto de envio obrigatório para a edição dos parâmetros do consentimento, exceto para o caso de edição exclusiva do campo “/data/creditors/name”.\\n\", \"required\": [ \"document\" ], \"properties\": { \"document\": { \"type\": \"object\", \"required\": [ \"identification\", \"rel\" ], \"properties\": { \"identification\": { \"type\": \"string\", \"maxLength\": 11, \"description\": \"Número do documento de identificação oficial do usuário logado na instituição iniciadora.\", \"example\": \"11111111111\", \"pattern\": \"^\\\\d{11}$\" }, \"rel\": { \"type\": \"string\", \"description\": \"Tipo do documento de identificação oficial do usuário logado na instituição iniciadora.\", \"enum\": [ \"CPF\" ] } } } } }, \"businessEntity\": { \"type\": \"object\", \"description\": \"Usuário (pessoa jurídica) que encontra-se logado na instituição Iniciadora de Pagamento. \\n\\n[Restrição] Preenchimento obrigatório se usuário logado na instituição Iniciadora de Pagamento for um CNPJ (pessoa jurídica).\\n\", \"required\": [ \"document\" ], \"properties\": { \"document\": { \"type\": \"object\", \"required\": [ \"identification\", \"rel\" ], \"properties\": { \"identification\": { \"type\": \"string\", \"maxLength\": 14, \"description\": \"Número do documento de identificação oficial do titular pessoa jurídica.\", \"example\": \"11111111111111\", \"pattern\": \"^[0-9A-Z]{12}[0-9]{2}$\" }, \"rel\": { \"type\": \"string\", \"maxLength\": 4, \"description\": \"Tipo do documento de identificação oficial do titular pessoa jurídica.\", \"example\": \"CNPJ\", \"pattern\": \"^[A-Z]{4}$\" } } } } } } }, { \"type\": \"object\", \"properties\": { \"status\": { \"type\": \"string\", \"enum\": [ \"REVOKED\" ], \"example\": \"REVOKED\", \"description\": \"Estado atual do consentimento de longa duração\\n\" }, \"revocation\": { \"type\": \"object\", \"description\": \"Objeto contendo as informações de revogação dos consentimentos de longa duração.\", \"required\": [ \"revokedBy\", \"revokedFrom\", \"reason\" ], \"properties\": { \"revokedBy\": { \"type\": \"string\", \"enum\": [ \"INICIADORA\", \"USUARIO\", \"DETENTORA\" ], \"example\": \"INICIADORA\", \"description\": \"Quem iniciou a solicitação de revogação \\n- INICIADORA\\n- USUARIO\\n- DETENTORA\\n\" }, \"revokedFrom\": { \"type\": \"string\", \"enum\": [ \"INICIADORA\", \"DETENTORA\" ], \"example\": \"DETENTORA\", \"description\": \"Canal onde iniciou-se o processo de revogação \\n- INICIADORA\\n- DETENTORA\\n\" }, \"reason\": { \"type\": \"object\", \"description\": \"Informações sobre o motivo da revogação\\n\", \"required\": [ \"code\", \"detail\" ], \"properties\": { \"code\": { \"type\": \"string\", \"enum\": [ \"REVOGADO_RECEBEDOR\", \"REVOGADO_USUARIO\", \"NAO_INFORMADO\" ], \"example\": \"REVOGADO_RECEBEDOR\", \"description\": \"Código indicador do motivo de revogação.\\n- REVOGADO_RECEBEDOR\\n- REVOGADO_USUARIO\\n- NAO_INFORMADO\\n\" }, \"detail\": { \"type\": \"string\", \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"maxLength\": 2048, \"description\": \"Detalhe sobre o motivo de revogação indicado no campo `/data/revocation/reason/code`.\\n- NAO_INFORMADO: Não informada pela detentora de conta;\\n- REVOGADO_USUARIO: O usuário pagador revogou a recorrência do consentimento;\\n- REVOGADO_RECEBEDOR: O usuário recebedor revogou a recorrência do consentimento.\\n\" } } } } } } }, { \"type\": \"object\", \"properties\": { \"status\": { \"type\": \"string\", \"enum\": [ \"REJECTED\" ], \"example\": \"REJECTED\", \"description\": \"Estado atual do consentimento de longa duração\\n\" }, \"rejection\": { \"type\": \"object\", \"description\": \"Objeto contendo as informações de rejeição dos consentimentos. \\n\", \"required\": [ \"rejectedBy\", \"rejectedFrom\", \"reason\" ], \"properties\": { \"rejectedBy\": { \"type\": \"string\", \"enum\": [ \"INICIADORA\", \"USUARIO\", \"DETENTORA\" ], \"example\": \"INICIADORA\", \"description\": \"Ator responsável pela solicitação rejeição\\n\" }, \"rejectedFrom\": { \"type\": \"string\", \"enum\": [ \"INICIADORA\", \"DETENTORA\" ], \"example\": \"DETENTORA\", \"description\": \"Canal onde iniciou-se o processo de rejeição \\n- INICIADORA\\n- DETENTORA\\n\" }, \"reason\": { \"type\": \"object\", \"description\": \"Informações sobre o motivo da rejeição \\n\", \"required\": [ \"code\", \"detail\" ], \"properties\": { \"code\": { \"type\": \"string\", \"enum\": [ \"NAO_INFORMADO\", \"FALHA_INFRAESTRUTURA\", \"TEMPO_EXPIRADO_AUTORIZACAO\", \"REJEITADO_USUARIO\", \"CONTAS_ORIGEM_DESTINO_IGUAIS\", \"CONTA_NAO_PERMITE_PAGAMENTO\", \"AUTENTICACAO_DIVERGENTE\", \"FLUXO_NAO_SUPORTADO_PRODUTO\" ], \"example\": \"AUTENTICACAO_DIVERGENTE\", \"description\": \"Código indicador do motivo de rejeição.\\n- NAO_INFORMADO\\n- FALHA_INFRAESTRUTURA\\n- TEMPO_EXPIRADO_AUTORIZACAO\\n- REJEITADO_USUARIO\\n- CONTAS_ORIGEM_DESTINO_IGUAIS\\n- CONTA_NAO_PERMITE_PAGAMENTO\\n- AUTENTICACAO_DIVERGENTE\\n- FLUXO_NAO_SUPORTADO_PRODUTO\\n\" }, \"detail\": { \"type\": \"string\", \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"maxLength\": 2048, \"description\": \"Detalhe sobre o motivo de rejeição indicado no campo `/data/rejection/reason/code`\\n- NAO_INFORMADO: Não informada pela detentora de conta;\\n- FALHA_INFRAESTRUTURA: [Descrição de qual falha na infraestrutura inviabilizou o processamento];\\n- TEMPO_EXPIRADO_AUTORIZACAO: Consentimento expirou antes que o usuário pudesse confirmá-lo;\\n- REJEITADO_USUARIO: O usuário rejeitou a autorização do consentimento;\\n- CONTAS_ORIGEM_DESTINO_IGUAIS: A conta selecionada é igual à conta destino e não permite realizar esse pagamento;\\n- CONTA_NAO_PERMITE_PAGAMENTO: A conta selecionada é do tipo [salario/investimento/liquidação/outros] e não permite realizar esse pagamento;\\n- AUTENTICACAO_DIVERGENTE : Usuário autenticado no detentor diverge do usuário autenticado no iniciador;\\n- FLUXO_NAO_SUPORTADO_PRODUTO: O consentimento está configurado para um produto ainda não suportado pelo fluxo que iniciou a solicitação.\\n\", \"example\": \"O usuário rejeitou a autorização do consentimento\" } } } } } } } ] } } } } }, \"description\": \"Payload para criação do consentimento para iniciação do pagamento.\", \"required\": true }, \"responses\": { \"200\": { \"description\": \"Objeto contendo as informações de consentimento para iniciação de pagamento automático.\", \"headers\": { \"x-fapi-interaction-id\": { \"description\": \"Um UUID [RFC4122](https://tools.ietf.org/html/rfc4122) usado como um ID de correlação entre request e response.",
